SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LPB ON LPB.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(LPB.TIPO) = LOWER('resumo de trabalhos') AND LOWER(LPB.NATUREZA) = LOWER('resumo expandido') AND COALESCE(CAST(NULLIF(CAST(CAST(COALESCE(LPB.ANO, '') AS INTEGER) AS TEXT) , '') AS INTEGER), -1) = 2022 AND LOWER(S.GENERO) = LOWER('feminino') AND LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'gyn'